/* --- ESTILIZAÇÃO PREMIUM DO LOOP DE CONSULTA (MODO FLUXO) --- */

/* Remove o sublinhado feio e ajusta a cor dos títulos */
.wp-block-post-title a {
    text-decoration: none !important;
    color: #1a202c !important; /* Cor escura e elegante */
    font-weight: 700;
    line-height: 1.3;
    transition: color 0.3s ease;
}

/* Efeito azul do Modo Fluxo ao passar o mouse no título */
.wp-block-post-title a:hover {
    color: #0073aa !important; /* Tom de azul da sua marca */
}

/* Arredonda as pontas das imagens e adiciona sombra leve */
.wp-block-post-featured-image img {
    border-radius: 8px !important;
    box-shadow: 0 4px 10px rgba(0,0,0,0.08) !important;
    transition: transform 0.3s ease;
}

/* Efeito de flutuar a imagem ao passar o mouse */
.wp-block-post:hover .wp-block-post-featured-image img {
    transform: translateY(-3px);
}

/* Dá um respiro e separa melhor um artigo do outro */
.wp-block-post {
    margin-bottom: 40px !important;
}

/* --- LIMPEZA DE LAYOUT: REMOVER SIDEBAR E COMENTÁRIOS --- */

/* 1. Força o layout de coluna única e centraliza o texto */
@media (min-width: 1024px) {
    .post-layout {
        grid-template-columns: 1fr !important; /* Remove o espaço de 300px da sidebar */
        max-width: 850px !important; /* Evita que o texto fique largo demais na tela */
        margin: 0 auto !important; /* Centraliza o artigo na página */
    }
}

/* 2. Oculta todos os elementos visuais da barra lateral */
.sidebar,
aside,
.widget-area,
.sidebar-widget {
    display: none !important;
}

/* 3. Remove completamente a seção de comentários */
.comments-area,
#comments,
.comment-respond {
    display: none !important;
}

/* --- ESTILIZAÇÃO DA NEWSLETTER (MODO FLUXO) --- */

.newsletter {
    background: linear-gradient(135deg, #0E3A6E, #159BA8);
    border-radius: 10px;
    padding: 40px 30px;
    text-align: center;
    color: #ffffff;
    margin: 40px 0;
    box-shadow: 0 4px 24px -4px rgba(21,155,168,0.3);
}

.newsletter h3 {
    font-size: 1.5rem;
    font-weight: 700;
    margin-bottom: 10px;
    color: #ffffff;
    font-family: 'Space Grotesk', system-ui, sans-serif;
}

.newsletter p {
    font-size: 1rem;
    opacity: 0.9;
    margin-bottom: 25px;
    max-width: 500px;
    margin-left: auto;
    margin-right: auto;
    font-family: 'Inter', system-ui, sans-serif;
}

.newsletter-form {
    display: flex;
    flex-direction: column;
    gap: 15px;
    max-width: 500px;
    margin: 0 auto;
}

@media (min-width: 640px) {
    .newsletter-form { 
        flex-direction: row; 
    }
}

.newsletter-form input[type="email"] {
    flex: 1;
    padding: 12px 20px;
    border-radius: 8px;
    border: 1px solid rgba(255, 255, 255, 0.3);
    background: rgba(255, 255, 255, 0.1);
    color: #ffffff;
    font-size: 1rem;
    outline: none;
    font-family: 'Inter', system-ui, sans-serif;
}

.newsletter-form input[type="email"]::placeholder {
    color: rgba(255, 255, 255, 0.7);
}

.newsletter-form button {
    padding: 12px 25px;
    border-radius: 8px;
    border: none;
    background: #ffffff;
    color: #0E3A6E;
    font-weight: 700;
    font-size: 1rem;
    cursor: pointer;
    transition: background 0.3s ease, transform 0.2s;
    font-family: 'Space Grotesk', system-ui, sans-serif;
}

.newsletter-form button:hover {
    background: #F5F8FA;
    transform: translateY(-2px);
}
